from flask import Flask, request, jsonify
import redis

app = Flask(__name__)
r = redis.StrictRedis(host='localhost', port=6379, db=0)

# Function for caching a function result using Redis for specified duration (in seconds)
def cache_function(duration):
    def decorator(func):
        def wrapper(*args, **kwargs):
            key = f"cache_{func.__name__}"
            result = r.get(key)
            if result is not None:
                return jsonify(result)

            result = func(*args, **kwargs)
            r.setex(key, duration, json.dumps(result))
            return result
        return wrapper
    return decorator

# Example of an expensive database query function to cache
@cache_function(60)  # Cache for 1 minute
def get_expensive_data():
    # Assume this is an expensive database query function
    data = [{'id': i, 'value': i * i} for i in range(1, 10)]
    return data

@app.route('/session')
def set_session():
    session_id = str(r.incr('session_id'))
    r.set(f"session:{session_id}", {"user": "John Doe", "role": "admin"})
    return jsonify({"session_id": session_id})

@app.route('/session/<string:session_id>')
def get_session(session_id):
    data = r.hgetall(f"session:{session_id}")
    if not data:
        return jsonify({"error": "Session not found."}), 404
    return jsonify(data)

@app.route('/expensive/<int:id>')
def get_expensive_data_by_id(id):
    return get_expensive_data()

